import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface TaskCount {
  column: string;
  count: number;
}

interface ProjectData {
  project: {
    name: string;
    totalTasks: number;
  };
  taskCounts: TaskCount[];
}

export default function Widget() {
  const projectData = response.data as ProjectData;
  const { project, taskCounts } = projectData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} color="primary">
              {project.name}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Total Tasks: {project.totalTasks}
            </Typography>
          </Box>

          <Stack direction="row" spacing={0.5}>
            {taskCounts.map((task, index) => (
              <Chip
                key={index}
                label={`${task.column}: ${task.count}`}
                sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: '#F3F4F6' }}
              />
            ))}
          </Stack>

          <BarChart
            height={120}
            series={[
              {
                data: taskCounts.map(task => task.count),
                color: '#3B82F6',
              },
            ]}
            xAxis={[
              {
                data: taskCounts.map(task => task.column),
                scaleType: 'band',
                tickLabelStyle: {
                  fontSize: 11,
                  fill: '#6B7280',
                },
              }
            ]}
            margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
            sx={{
              '& .MuiBarElement-root': {
                rx: 4,
              },
            }}
          />
        </Stack>
      </CardContent>
    </Card>
  );
}
